// frontend/src/components/Layout.js
import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import Theme from './Theme';

import pic5 from '../components/gmail.png';
import pic6 from '../components/facebook.png';

// Also import the chef logo from src/
import logo from '../pictures/LogoK.jpg';

const Layout = ({ children }) => {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate  = useNavigate();

  const isActive = (path) => location.pathname === path ? 'active' : '';

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <>
      {/* ── Header ── */}
      <header>
        <div className="header-container">
          <img src={logo} alt="Chef Logo" className="header-logo" />
          <h1>TRAVEL JOURNAL</h1>
        </div>
        {/* Dark mode toggle button */}
        <Theme />
      </header>

      {/* ── Navigation ── */}
      <nav className="horizontal-nav">
        <ul>
          <li><Link to="/home"    className={isActive('/home')}>Home</Link></li>
          <li><Link to="/about"   className={isActive('/about')}>About</Link></li>
          <li><Link to="/contact" className={isActive('/contact')}>Contact</Link></li>

          {/* Logged OUT */}
          {!user && (
            <>
              <li><Link to="/register" className={isActive('/register')}>Register</Link></li>
              <li><Link to="/login"    className={isActive('/login')}>Login</Link></li>
            </>
          )}

          {/* Logged IN */}
          {user && (
            <>
              <li><Link to="/create-post" className={isActive('/create-post')}>Write Post</Link></li>
              <li><Link to="/profile"     className={isActive('/profile')}>Profile</Link></li>
              {user.role === 'admin' && (
                <li><Link to="/admin" className={isActive('/admin')}>Admin</Link></li>
              )}
              <li>
                <button className="nav-logout-btn" onClick={handleLogout}>
                  Logout ({user.name})
                </button>
              </li>
            </>
          )}
        </ul>
      </nav>

      {/* ── Page Content ── */}
      <main>{children}</main>

      {/* ── Footer ── */}
      <footer className="footer">
        <div style={{ display: 'flex', justifyContent: 'center', gap: '24px', flexWrap: 'wrap', marginBottom: '4px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <img src={pic5} alt="Gmail" style={{ width: '22px', height: '22px', borderRadius: '4px', border: 'none', margin: 0 }} />
            <span>krishanepadilla@gmail.com</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <img src={pic6} alt="Facebook" style={{ width: '22px', height: '22px', borderRadius: '4px', border: 'none', margin: 0 }} />
            <span>krishanepadilla@facebook.com</span>
          </div>
        </div>
        <p>&copy; 2026 Student Portfolio</p>
      </footer>
    </>
  );
};

export default Layout;
